previewCss:
.darma-loader-darma-custom-534 {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
   display: inline-flex;
   gap: 10px;
}
.darma-loader-darma-custom-534:before, .darma-loader-darma-custom-534:after  {
  content: "";
   height: 20px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: radial-gradient(farthest-side,currentColor 95%,#0000) 50%/8px 8px no-repeat currentColor;
   aspect-ratio: 1;
   animation: darma-loader-darma-custom-534-l10 1.5s infinite alternate;
}
.darma-loader-darma-custom-534:after  {
  --s:-1;
}
@keyframes darma-loader-darma-custom-534-l10  {
  0% ,20% {transform:scaleX(var(--s,1)) rotate(0deg) ;
  clip-path:inset(0)}
60%,100%{transform:scaleX(var(--s,1)) rotate(30deg);
  clip-path:inset(40% 0 0)}
}

